import{_ as e,o as a,c as l,a3 as r}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"Agent 编辑器指南","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/agents/editor-guide.md","filePath":"user-guide/tools/llm-chat/agents/editor-guide.md","lastUpdated":1778244893000}'),i={name:"user-guide/tools/llm-chat/agents/editor-guide.md"};function n(o,t,s,g,d,h){return a(),l("div",null,[...t[0]||(t[0]=[r('<div><h1 id="agent-编辑器指南" tabindex="-1">Agent 编辑器指南 <a class="header-anchor" href="#agent-编辑器指南" aria-label="Permalink to &quot;Agent 编辑器指南&quot;">​</a></h1><p>Agent 编辑器是定义智能体行为、外观和能力的核心界面。它采用左侧导航、右侧表单的分段式结构，确保即使在配置项极多时也能保持清晰。</p><h2 id="_1-基础设定-basic" tabindex="-1">1. 基础设定 (Basic) <a class="header-anchor" href="#_1-基础设定-basic" aria-label="Permalink to &quot;1. 基础设定 (Basic)&quot;">​</a></h2><p>管理 Agent 的身份标识和组织方式：</p><ul><li><strong>ID/名称</strong>: Agent 的唯一内部标识符，用于数据存储。</li><li><strong>显示名称</strong>: 在聊天界面和列表中展示的友好名称。</li><li><strong>图标</strong>: 支持上传本地图片、选择 Emoji 或使用系统内置图标库。</li><li><strong>分类与标签</strong>: 通过标签对 Agent 进行归类，方便在大型 Agent 库中快速检索。</li><li><strong>描述</strong>: 对 Agent 的功能、背景或使用建议的简要介绍。</li></ul><h2 id="_2-创建与导入" tabindex="-1">2. 创建与导入 <a class="header-anchor" href="#_2-创建与导入" aria-label="Permalink to &quot;2. 创建与导入&quot;">​</a></h2><h3 id="从零创建" tabindex="-1">从零创建 <a class="header-anchor" href="#从零创建" aria-label="Permalink to &quot;从零创建&quot;">​</a></h3><ol><li>在左侧 Agent 列表顶部点击 <strong>➕ (创建新智能体)</strong> 按钮。</li><li>填写基础信息并选择默认的服务渠道与模型。</li><li>根据需要配置系统提示词（System Prompt）。</li></ol><h3 id="复制已有-agent" tabindex="-1">复制已有 Agent <a class="header-anchor" href="#复制已有-agent" aria-label="Permalink to &quot;复制已有 Agent&quot;">​</a></h3><p>右键点击 Agent 条目选择 <strong>「复制」</strong>。系统会创建一个包含所有配置、预设消息以及私有资产目录完整副本的新 Agent。</p><h3 id="导入-sillytavern-角色卡" tabindex="-1">导入 SillyTavern 角色卡 <a class="header-anchor" href="#导入-sillytavern-角色卡" aria-label="Permalink to &quot;导入 SillyTavern 角色卡&quot;">​</a></h3><p>系统深度兼容 SillyTavern 格式（PNG 角色卡或 JSON）：</p><ol><li>在创建界面选择 <strong>「导入 SillyTavern 角色卡」</strong>。</li><li>导入后，系统会自动解析并填充：名称、描述、性格设定、场景描述、开场白（预设消息）以及关联的资产图片。</li></ol><h2 id="_3-环境增强-environment" tabindex="-1">3. 环境增强 (Environment) <a class="header-anchor" href="#_3-环境增强-environment" aria-label="Permalink to &quot;3. 环境增强 (Environment)&quot;">​</a></h2><p>通过插件扩展 Agent 的感知能力。启用后，插件提供的信息将通过 <code>{{tool_context}}</code> 宏注入到提示词中。</p><ul><li><strong>总开关</strong>: 控制环境增强功能的全局启用。</li><li><strong>可用插件列表</strong>: <ul><li><strong>系统状态</strong>: 注入当前 CPU、内存、电池等硬件状态。</li><li><strong>剪贴板</strong>: 获取最新的剪贴板文本内容。</li><li><strong>运行时上下文</strong>: 注入当前时间、日期、操作系统版本等信息。</li></ul></li><li><strong>默认策略</strong>: 可设置新发现的插件是否默认启用。</li></ul><h2 id="_4-输出与显示-output" tabindex="-1">4. 输出与显示 (Output) <a class="header-anchor" href="#_4-输出与显示-output" aria-label="Permalink to &quot;4. 输出与显示 (Output)&quot;">​</a></h2><p>控制 Agent 的交互行为和视觉渲染风格：</p><ul><li><strong>分支发送模式</strong>: 开启后，点击 LLM 生成的交互按钮（如 RPG 游戏中的选项）时，系统会从该消息节点创建新分支，而不是在对话末尾追加，非常适合多分支剧情探索。</li><li><strong>工具调用折叠</strong>: 开启后，繁琐的工具调用过程（JSON 参数和原始返回结果）在聊天流中默认折叠。</li><li><strong>媒体音量</strong>: 为该 Agent 设置独立的音量倍率，平衡不同角色的语音输出大小。</li><li><strong>文本替换规则 (Regex)</strong>: 允许配置 Agent 专属的<a href="./../context-pipeline/regex-pipeline">正则管道</a>，用于实时清洗输出内容。</li><li><strong>思考块规则</strong>: 配置如何识别和展示 LLM 的思考过程（如 <code>&lt;think&gt;</code> 标签内容）。</li><li><strong>回复样式自定义</strong>: 支持通过 CSS 变量自定义 Markdown 渲染效果（如发光文字、特定角色主题色）。</li><li><strong>视觉化输出指南</strong>: 一个专用的文本编辑器，用于存放 HTML/CSS/JS 渲染规范，引导模型输出符合 UI 框架要求的结构化视觉内容。</li></ul><h2 id="_5-用户档案与会话变量" tabindex="-1">5. 用户档案与会话变量 <a class="header-anchor" href="#_5-用户档案与会话变量" aria-label="Permalink to &quot;5. 用户档案与会话变量&quot;">​</a></h2><ul><li><strong>关联用户档案</strong>: 绑定特定的<a href="./user-profiles">用户档案</a>，使 Agent 能够感知“你是谁”。</li><li><strong>会话变量 (Variables)</strong>: 定义动态变量（如“好感度”、“金钱”），并在提示词中通过 <code>{{var_name}}</code> 引用。详见<a href="./../macro-system/session-variables">变量系统</a>。</li></ul><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./parameters">参数配置与预设消息</a></li><li><a href="./virtual-timeline">虚拟时间线</a></li><li><a href="./../tool-calling/index">工具调用配置</a></li></ul></div>',1)])])}const p=e(i,[["render",n]]);export{c as __pageData,p as default};
